import { proxyActivities } from '@temporalio/workflow';
import type * as activities from './activities';

const { fetchData } = proxyActivities<typeof activities>({
  startToCloseTimeout: '30 seconds',
});

export async function FetchUrlWorkflow(url: string): Promise<string> {
  return await fetchData(url);
}

import { NativeConnection, Worker } from '@temporalio/worker';
import { Connection, Client } from '@temporalio/client';
import { FetchUrlWorkflow } from './workflows';
import * as activities from './activities';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE || 'default';
  const apiKey = process.env.TEMPORAL_API_KEY;
  const runId = process.env.ZEALT_RUN_ID || 'local';

  if (!address || !apiKey) {
    throw new Error("TEMPORAL_ADDRESS and TEMPORAL_API_KEY must be set");
  }

  // Worker Connection
  const workerConnection = await NativeConnection.connect({
    address,
    tls: true,
  });

  // Note: For NativeConnection with apiKey, we can pass it in metadata or wait, the Temporal SDK supports apiKey directly on options?
  // Actually, NativeConnection options doesn't have apiKey directly in older versions? Wait, in 1.11.4 it does!
  // Let me fix the connection config.
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

import { NativeConnection, Worker } from '@temporalio/worker';
import { Connection, Client } from '@temporalio/client';
import { FetchUrlWorkflow } from './workflows';
import * as activities from './activities';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE || 'default';
  const apiKey = process.env.TEMPORAL_API_KEY;
  const runId = process.env.ZEALT_RUN_ID || 'local';

  if (!address || !apiKey) {
    throw new Error("TEMPORAL_ADDRESS and TEMPORAL_API_KEY must be set");
  }

  const connectionOptions = {
    address,
    tls: true,
    apiKey,
  };

  // Worker Connection
  const workerConnection = await NativeConnection.connect(connectionOptions);

  const worker = await Worker.create({
    connection: workerConnection,
    namespace,
    taskQueue: 'fetch-url-ts',
    workflowsPath: require.resolve('./workflows'),
    activities,
  });

  const workerPromise = worker.run();

  // Client Connection
  const clientConnection = await Connection.connect(connectionOptions);

  const client = new Client({
    connection: clientConnection,
    namespace,
  });

  const workflowId = `fetch-wf-${runId}`;

  try {
    const handle = await client.workflow.start(FetchUrlWorkflow, {
      taskQueue: 'fetch-url-ts',
      workflowId,
      args: ['https://api.github.com/zen'],
    });

    const result = await handle.result();
    console.log(result);
  } finally {
    worker.shutdown();
    await workerPromise;
  }
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

